SELECT EXISTS (
    SELECT 1
    FROM receipt_files
    WHERE expense_item_id = #{expenseItemId}
)

SELECT EXISTS (
    SELECT 1
    FROM receipt_files rf
    INNER JOIN expense_items ei ON ei.id = rf.expense_item_id
    WHERE ei.expense_application_id = #{expenseApplicationId}
)

SELECT

