mapper.update:
UPDATE receipt_files
SET state = #{newState},
    activated_at = CASE
        WHEN #{newState} = 'ACTIVE' THEN #{activatedAt}
        ELSE activated_at
    END,
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND state = #{expectedState}

mapper.delete:
